B.LG=new A.j(!0,B.en,null,null,null,null,16,B.ak,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.OU=new A.aI("COD (Bayar di Tempat)",null,B.LG,null,null)
B.OW=new A.aI("10. Kelayakan Pengguna (Eligibility)",null,B.as,null,null)
B.OX=new A.aI("11. Keamanan Akun",null,B.as,null,null)
B.OY=new A.aI("2. Keamanan Data",null,B.as,null,null)
B.OZ=new A.aI("Jika Pengguna memiliki pertanyaan, Masukkan, atau keluhan terkait kebijakan privasi ini, silakan hubungi tim layanan pelanggan kami melalui toko.barokah.material@gmail.com atau melalui menu chat yang sudah kami sediakan.",null,B.a9,null,null)
B.P_=new A.aI("3. Hak Pengguna",null,B.as,null,null)
B.P0=new A.aI("14. Batasan Tanggung Jawab (Disclaimer)",null,B.as,null,null)
B.P1=new A.aI('Kami (Pihak Toko) tidak bertanggung jawab atas kerugian secara tidak langsung, kerugian operasional, atau kerugian tak berwujud yang timbul dari penggunaan aplikasi. Aplikasi disediakan "sebagaimana adanya" tanpa jaminan bahwa aplikasi akan selalu bebas dari error atau gangguan teknis.',null,B.a9,null,null)
B.P2=new A.aI("13. Kekayaan Intelektual (Hak Cipta)",null,B.as,null,null)
B.P3=new A.aI("Kami (Pihak Toko) berkomitmen penuh menjaga kerahasiaan data pribadi Pengguna. Kami tidak akan pernah menjual, menyewakan, atau menyebarluaskan data pribadi Pengguna kepada pihak ketiga mana pun tanpa persetujuan Anda.",null,B.a9,null,null)
B.P5=new A.aI("Alamat & Operasional",null,B.jn,null,null)
B.P6=new A.aI("1).  Proses Pengiriman: Estimasi waktu pengiriman sepenuhnya merujuk pada ketentuan dan jangka waktu yang ditetapkan oleh pihak kurir yang dipilih oleh Pengguna.\n2).  Syarat Komplain: Pengajuan komplain wajib disertai dengan bukti video unboxing paket yang direkam secara utuh tanpa jeda, tanpa edit, dan tanpa terpotong. Pengajuan komplain wajib disampaikan kepada pihak Toko Barokah dalam kurun waktu maksimal 1x24 jam setelah paket dinyatakan diterima berdasarkan status pelacakan kurir.\n3).  Ketentuan Pengembalian Barang (Retur): Proses pengembalian barang (retur) dilakukan berdasarkan kesepakatan awal antara Pembeli dan Penjual. Jika komplain yang diajukan Pembeli divalidasi dan kesepakatan pengembalian barang tercapai, Pengguna wajib mengikuti instruksi yang diberikan oleh pihak Penjual terkait prosedur, waktu, dan metode pengembalian barang.",null,B.a9,null,null)
B.P7=new A.aI("Hubungi Kami",null,B.dK,null,null)
B.P8=new A.aI("Toko Barokah menghormati privasi Anda. Kebijakan Privasi ini menjelaskan bagaimana kami mengumpulkan, menggunakan, dan melindungi informasi Anda saat menggunakan aplikasi mobile kami.",null,B.a9,null,null)
B.P9=new A.aI("Pengguna wajib memastikan seluruh informasi data diri yang disampaikan saat proses pendaftaran maupun transaksi di aplikasi Toko Barokah adalah benar, valid, akurat, dan lengkap. Segala bentuk kerugian yang timbul akibat ketidakakuratan data yang diberikan oleh Pengguna menjadi tanggung jawab penuh Pengguna. Harga dapat berubah sewaktu-waktu tanpa pemberitahuan, namun tidak akan mempengaruhi pesanan yang sudah dibayar.",null,B.a9,null,null)
B.Pb=new A.aI("\u2022 Memproses dan mengelola pesanan.\n\u2022 Menghubungi Pelanggan terkait status pesanan atau kendala pengiriman.\n\u2022 Meningkatkan layanan aplikasi dan pengalaman berbelanja.",null,B.a9,null,null)
B.Pc=new A.aI("Keamanan data Anda adalah prioritas kami. Kami menggunakan enkripsi standar industri untuk melindungi transaksi finansial Anda (QRIS) dan memastikan data kurir pengiriman COD internal kami dikelola dengan aman.Pengguna berhak untuk mengakses, memperbaiki, atau meminta penghapusan data pribadi yang tersimpan dalam sistem kami dengan menghubungi layanan pelanggan resmi toko.barokah.material@gmail.com atau melalui menu chat yang sudah kami sediakan. Kami akan merespons permintaan tersebut sesuai dengan prosedur verifikasi yang berlaku.",null,B.a9,null,null)
B.Pd=new A.aI("Kami (Pihak Toko) berhak mengubah atau memperbarui Syarat dan Ketentuan ini kapan saja. Perubahan akan berlaku segera setelah diunggah di aplikasi. Penggunaan aplikasi yang berkelanjutan setelah perubahan dianggap sebagai persetujuan Pengguna atas ketentuan yang baru.",null,B.a9,null,null)
B.Pe=new A.aI("pengguna harus berusia minimal 17 tahun, atau jika di bawah umur, harus di bawah pengawasan orang tua/wali. Juga menyatakan bahwa pengguna tidak sedang dicekal oleh hukum untuk melakukan transaksi.",null,B.a9,null,null)
B.Pf=new A.aI("15. Hukum yang Berlaku",null,B.as,null,null)
B.Pg=new A.aI("6. Penggunaan Data",null,B.as,null,null)
B.MS=new A.j(!0,B.a2,null,null,null,null,20,B.ak,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.Ph=new A.aI("Toko Barokah",null,B.MS,null,null)
B.Pi=new A.aI("4. Perubahan Kebijakan Privasi",null,B.as,null,null)
B.Pj=new A.aI("6 Kategori Produk Unggulan Kami",null,B.dK,null,null)
B.Pk=new A.aI("Metode Pembayaran Aman & Fleksibel",null,B.dK,null,null)
B.Pl=new A.aI("Pengguna bertanggung jawab penuh menjaga kerahasiaan password dan data login. Segala aktivitas yang terjadi di bawah akun tersebut dianggap sebagai aktivitas Pengguna. Pengguna wajib segera melapor jika terdapat aktivitas yang mencurigakan penggunaan akun tanpa izin.",null,B.a9,null,null)
B.Pm=new A.aI("Syarat dan Ketentuan ini diatur dan ditafsirkan sesuai dengan hukum Negara Republik Indonesia. Setiap sengketa yang timbul akan diselesaikan secara musyawarah/kekeluargaan.",null,B.a9,null,null)
B.Pn=new A.aI("Kami mengumpulkan dan mengolah data pribadi Pengguna, termasuk namun tidak terbatas pada nama lengkap, nomor telepon, dan data lokasi (GPS), yang digunakan secara terbatas untuk tujuan operasional, yakni verifikasi identitas serta memastikan akurasi pengiriman pesanan oleh tim logistik kami.",null,B.a9,null,null)
B.N3=new A.j(!0,B.qE,null,null,null,null,15,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.Po=new A.aI("Kami menyediakan berbagai macam pilihan produk terbaik untuk mendukung segala keperluan pembangunan, hobi, dan perbaikan rumah Anda.",null,B.N3,B.aJ,null)
B.Pp=new A.aI("Semua konten di dalam aplikasi Toko Barokah (logo, desain, teks, grafis, foto produk) adalah milik Toko Barokah dan dilindungi hak cipta. Pengguna dilarang menyalin, menyebarluaskan, atau menggunakannya untuk kepentingan komersial tanpa izin tertulis.",null,B.a9,null,null)
B.Pq=new A.aI("16. Perubahan Syarat Kebijakan dan Ketentuan",null,B.as,null,null)
B.Pr=new A.aI("Kami (Pihak Toko) berhak membatalkan pesanan jika stok habis secara tidak terduga, terjadi kesalahan harga/informasi produk yang nyata, adanya indikasi kecurangan transaksi, atau kegagalan pembayaran oleh Pembeli dalam batas waktu yang ditentukan.",null,B.a9,null,null)
